eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cLesson12: () => (/* binding */ cLesson12)\n/* harmony export */ });\nconst cLesson12 = {\n    id: 12,\n    title: \"Advanced Pointers & Function Pointers\",\n    description: \"Pointers to pointers, function pointers, and callbacks.\",\n    content: `\r\n## Advanced Pointer Concepts\r\n\r\n### Pointers to Pointers:\r\n<COMPILER>\r\n#include <stdio.h>\r\n\r\nint main() {\r\n    int x = 10;\r\n    int *p = &x;      // Pointer to int\r\n    int **pp = &p;    // Pointer to pointer to int\r\n    \r\n    printf(\"x = %d\\\\n\", x);\r\n    printf(\"*p = %d\\\\n\", *p);      // 10\r\n    printf(\"**pp = %d\\\\n\", **pp);  // 10\r\n    \r\n    // Modify x through pp\r\n    **pp = 99;\r\n    printf(\"x is now: %d\\\\n\", x);  // 99\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Function Pointers:\r\n<COMPILER>\r\n#include <stdio.h>\r\n\r\nint add(int a, int b) {\r\n    return a + b;\r\n}\r\n\r\nint multiply(int a, int b) {\r\n    return a * b;\r\n}\r\n\r\nint main() {\r\n    // Declare function pointer\r\n    int (*operation)(int, int);\r\n    \r\n    // Point to add function\r\n    operation = add;\r\n    printf(\"add(5, 3) = %d\\\\n\", operation(5, 3));  // 8\r\n    \r\n    // Point to multiply function\r\n    operation = multiply;\r\n    printf(\"multiply(5, 3) = %d\\\\n\", operation(5, 3));  // 15\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Callbacks Using Function Pointers:\r\n<COMPILER>\r\n#include <stdio.h>\r\n\r\ntypedef int (*Comparator)(int, int);\r\n\r\nint ascending(int a, int b) {\r\n    return a - b;\r\n}\r\n\r\nint descending(int a, int b) {\r\n    return b - a;\r\n}\r\n\r\nvoid sort_with_callback(int arr[], int n, Comparator compare) {\r\n    for (int i = 0; i < n - 1; i++) {\r\n        for (int j = 0; j < n - i - 1; j++) {\r\n            if (compare(arr[j], arr[j + 1]) > 0) {\r\n                int temp = arr[j];\r\n                arr[j] = arr[j + 1];\r\n                arr[j + 1] = temp;\r\n            }\r\n        }\r\n    }\r\n}\r\n\r\nint main() {\r\n    int arr[] = {5, 2, 8, 1, 9};\r\n    int n = 5;\r\n    \r\n    printf(\"Original: \");\r\n    for (int i = 0; i < n; i++) printf(\"%d \", arr[i]);\r\n    printf(\"\\\\n\");\r\n    \r\n    sort_with_callback(arr, n, ascending);\r\n    printf(\"Ascending: \");\r\n    for (int i = 0; i < n; i++) printf(\"%d \", arr[i]);\r\n    printf(\"\\\\n\");\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Array of Function Pointers:\r\n<COMPILER>\r\n#include <stdio.h>\r\n\r\nint add(int a, int b) { return a + b; }\r\nint sub(int a, int b) { return a - b; }\r\nint mul(int a, int b) { return a * b; }\r\n\r\nint main() {\r\n    // Array of function pointers\r\n    int (*operations[3])(int, int) = {add, sub, mul};\r\n    \r\n    printf(\"10 + 5 = %d\\\\n\", operations[0](10, 5));  // add\r\n    printf(\"10 - 5 = %d\\\\n\", operations[1](10, 5));  // sub\r\n    printf(\"10 * 5 = %d\\\\n\", operations[2](10, 5));  // mul\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/c/cLesson12.js\n");

