eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cppLesson12: () => (/* binding */ cppLesson12)\n/* harmony export */ });\nconst cppLesson12 = {\n    id: 12,\n    title: \"Advanced Data Structures\",\n    description: \"Implementing linked lists, trees, and graphs from scratch.\",\n    content: `\r\n## Implementing Data Structures in C++\r\n\r\nUnderstanding data structures at the implementation level is crucial for technical interviews and systems programming.\r\n\r\n### Singly Linked List:\r\n<COMPILER>\r\n#include <iostream>\r\nusing namespace std;\r\n\r\nstruct Node {\r\n    int data;\r\n    Node* next;\r\n    Node(int d) : data(d), next(nullptr) {}\r\n};\r\n\r\nclass LinkedList {\r\n    Node* head;\r\npublic:\r\n    LinkedList() : head(nullptr) {}\r\n    \r\n    ~LinkedList() {\r\n        Node* curr = head;\r\n        while (curr) {\r\n            Node* next = curr->next;\r\n            delete curr;\r\n            curr = next;\r\n        }\r\n    }\r\n    \r\n    void push_front(int val) {\r\n        Node* newNode = new Node(val);\r\n        newNode->next = head;\r\n        head = newNode;\r\n    }\r\n    \r\n    void push_back(int val) {\r\n        Node* newNode = new Node(val);\r\n        if (!head) { head = newNode; return; }\r\n        Node* curr = head;\r\n        while (curr->next) curr = curr->next;\r\n        curr->next = newNode;\r\n    }\r\n    \r\n    void print() {\r\n        Node* curr = head;\r\n        while (curr) {\r\n            cout << curr->data;\r\n            if (curr->next) cout << \" -> \";\r\n            curr = curr->next;\r\n        }\r\n        cout << \" -> NULL\" << endl;\r\n    }\r\n    \r\n    void reverse() {\r\n        Node* prev = nullptr;\r\n        Node* curr = head;\r\n        while (curr) {\r\n            Node* next = curr->next;\r\n            curr->next = prev;\r\n            prev = curr;\r\n            curr = next;\r\n        }\r\n        head = prev;\r\n    }\r\n};\r\n\r\nint main() {\r\n    LinkedList list;\r\n    list.push_back(1);\r\n    list.push_back(2);\r\n    list.push_back(3);\r\n    list.push_front(0);\r\n    \r\n    cout << \"List: \";\r\n    list.print();\r\n    \r\n    list.reverse();\r\n    cout << \"Reversed: \";\r\n    list.print();\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Binary Search Tree:\r\n\\`\\`\\`cpp\r\nstruct TreeNode {\r\n    int val;\r\n    TreeNode* left;\r\n    TreeNode* right;\r\n    TreeNode(int v) : val(v), left(nullptr), right(nullptr) {}\r\n};\r\n\r\nclass BST {\r\n    TreeNode* root;\r\n    \r\n    TreeNode* insert(TreeNode* node, int val) {\r\n        if (!node) return new TreeNode(val);\r\n        if (val < node->val) node->left = insert(node->left, val);\r\n        else if (val > node->val) node->right = insert(node->right, val);\r\n        return node;\r\n    }\r\n    \r\n    void inorder(TreeNode* node) {\r\n        if (!node) return;\r\n        inorder(node->left);\r\n        cout << node->val << \" \";\r\n        inorder(node->right);\r\n    }\r\n    \r\npublic:\r\n    BST() : root(nullptr) {}\r\n    void insert(int val) { root = insert(root, val); }\r\n    void inorder() { inorder(root); cout << endl; }\r\n};\r\n\r\nint main() {\r\n    BST tree;\r\n    for (int v : {5, 3, 7, 1, 4, 6, 8}) {\r\n        tree.insert(v);\r\n    }\r\n    tree.inorder(); // Sorted: 1 3 4 5 6 7 8\r\n}\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/cpp/cppLesson12.js\n");

