eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cppLesson2: () => (/* binding */ cppLesson2)\n/* harmony export */ });\nconst cppLesson2 = {\n    id: 2,\n    title: \"Control Flow\",\n    description: \"C++ If-statements, Loops, and Structs.\",\n    content: `\r\n## Control Flow in C++\r\n\r\nC++ control structures define the flow of execution in your application. They are practically identical to Java and C.\r\n\r\n### Conditionals\r\n\\`\\`\\`cpp\r\nint age = 18;\r\n\r\nif (age < 18) {\r\n    cout << \"Minor\" << endl;\r\n} else if (age == 18) {\r\n    cout << \"Just became an adult!\" << endl;\r\n} else {\r\n    cout << \"Adult\" << endl;\r\n}\r\n\\`\\`\\`\r\n\r\n### Switch Statements\r\nExtremely fast lookups used alongside \\`int\\`, \\`char\\`, and \\`enum\\`.\r\n\\`\\`\\`cpp\r\nchar rank = 'B';\r\nswitch(rank) {\r\n    case 'A': cout << \"Excellent\"; break;\r\n    case 'B': cout << \"Good\"; break;\r\n    case 'C': cout << \"Average\"; break;\r\n    default: cout << \"Invalid rank\";\r\n}\r\n\\`\\`\\`\r\n\r\n### Loops\r\n**For Loop:** (Perfect for iteration)\r\n\\`\\`\\`cpp\r\nfor(int i = 0; i < 5; i++) {\r\n    cout << i << \" \";\r\n}\r\n\\`\\`\\`\r\n\r\n**While Loop:** (Perfect for truth-conditions)\r\n\\`\\`\\`cpp\r\nint count = 10;\r\nwhile(count > 0) {\r\n    cout << count << endl;\r\n    count--;\r\n}\r\n\\`\\`\\`\r\n\r\n### Structs (Precursor to objects)\r\nUsed to package a group of disparate variables into a single conceptual package.\r\n\\`\\`\\`cpp\r\nstruct Person {\r\n    string name;\r\n    int age;\r\n    double height;\r\n};\r\n\r\nint main() {\r\n    Person p1;\r\n    p1.name = \"Alice\";\r\n    p1.age = 22;\r\n    p1.height = 1.70;\r\n}\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/cpp/cppLesson2.js\n");

