eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cppLesson6: () => (/* binding */ cppLesson6)\n/* harmony export */ });\nconst cppLesson6 = {\n    id: 6,\n    title: \"Templates & Generic Programming\",\n    description: \"Writing type-safe, reusable code with C++ Templates.\",\n    content: `\r\n## Templates in C++\r\n\r\nTemplates allow you to write generic code that works with **any data type**. This is the foundation of the Standard Template Library (STL) itself.\r\n\r\n### Function Templates\r\nA function template creates a family of functions — one per data type used.\r\n\r\n<COMPILER>\r\n#include <iostream>\r\nusing namespace std;\r\n\r\n// T is a placeholder for any type\r\ntemplate <typename T>\r\nT getMax(T a, T b) {\r\n    return (a > b) ? a : b;\r\n}\r\n\r\n// Works with any comparable type!\r\ntemplate <typename T>\r\nvoid swap(T &a, T &b) {\r\n    T temp = a;\r\n    a = b;\r\n    b = temp;\r\n}\r\n\r\nint main() {\r\n    cout << getMax(10, 20) << endl;          // Works with int\r\n    cout << getMax(3.14, 2.71) << endl;      // Works with double\r\n    cout << getMax('A', 'Z') << endl;        // Works with char\r\n    \r\n    int x = 5, y = 10;\r\n    swap(x, y);\r\n    cout << \"After swap: x=\" << x << \" y=\" << y << endl;\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Class Templates\r\nYou can also templatize entire classes.\r\n\r\n<COMPILER>\r\n#include <iostream>\r\nusing namespace std;\r\n\r\ntemplate <typename T>\r\nclass Stack {\r\nprivate:\r\n    T data[100];\r\n    int top;\r\n    \r\npublic:\r\n    Stack() : top(-1) {}\r\n    \r\n    void push(T val) {\r\n        data[++top] = val;\r\n        cout << \"Pushed: \" << val << endl;\r\n    }\r\n    \r\n    T pop() {\r\n        if (top < 0) {\r\n            cout << \"Stack is empty!\" << endl;\r\n            return T();\r\n        }\r\n        return data[top--];\r\n    }\r\n    \r\n    bool isEmpty() {\r\n        return top == -1;\r\n    }\r\n};\r\n\r\nint main() {\r\n    Stack<int> intStack;\r\n    intStack.push(10);\r\n    intStack.push(20);\r\n    intStack.push(30);\r\n    cout << \"Popped: \" << intStack.pop() << endl;\r\n    \r\n    Stack<string> strStack;\r\n    strStack.push(\"Hello\");\r\n    strStack.push(\"World\");\r\n    cout << \"Popped: \" << strStack.pop() << endl;\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Template Specialization\r\nYou can provide a specific implementation for a particular data type.\r\n\\`\\`\\`cpp\r\n// Generic template\r\ntemplate <typename T>\r\nvoid printType(T val) {\r\n    cout << \"Generic: \" << val << endl;\r\n}\r\n\r\n// Specialization for bool\r\ntemplate <>\r\nvoid printType<bool>(bool val) {\r\n    cout << \"Boolean: \" << (val ? \"true\" : \"false\") << endl;\r\n}\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/cpp/cppLesson6.js\n");

