eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cppLesson7: () => (/* binding */ cppLesson7)\n/* harmony export */ });\nconst cppLesson7 = {\n    id: 7,\n    title: \"Exception Handling\",\n    description: \"Writing robust code that handles runtime errors gracefully.\",\n    content: `\r\n## Exception Handling in C++\r\n\r\nExceptions provide a way to react to exceptional circumstances (like runtime errors) in programs by transferring control to special functions called **handlers**.\r\n\r\n### Basic try-catch-throw:\r\n\r\n<COMPILER>\r\n#include <iostream>\r\n#include <stdexcept>\r\nusing namespace std;\r\n\r\ndouble safeDivide(double a, double b) {\r\n    if (b == 0) {\r\n        throw runtime_error(\"Division by zero is not allowed!\");\r\n    }\r\n    return a / b;\r\n}\r\n\r\nint main() {\r\n    try {\r\n        cout << safeDivide(10, 2) << endl;   // Works fine: 5\r\n        cout << safeDivide(10, 0) << endl;   // Throws!\r\n    } catch (const runtime_error& e) {\r\n        cout << \"Caught error: \" << e.what() << endl;\r\n    }\r\n    \r\n    // Multiple catch blocks\r\n    try {\r\n        int arr[5] = {1, 2, 3, 4, 5};\r\n        throw out_of_range(\"Array index out of bounds!\");\r\n    } catch (const out_of_range& e) {\r\n        cout << \"Range Error: \" << e.what() << endl;\r\n    } catch (const exception& e) {\r\n        cout << \"General Error: \" << e.what() << endl;\r\n    } catch (...) {\r\n        cout << \"Unknown error occurred!\" << endl;\r\n    }\r\n    \r\n    return 0;\r\n}\r\n</COMPILER>\r\n\r\n### Custom Exception Classes\r\nYou can create your own exception types by inheriting from \\`std::exception\\`.\r\n\r\n<COMPILER>\r\n#include <iostream>\r\n#include <exception>\r\nusing namespace std;\r\n\r\n// Custom exception class\r\nclass InsufficientFundsException : public exception {\r\nprivate:\r\n    double amount;\r\npublic:\r\n    InsufficientFundsException(double a) : amount(a) {}\r\n    \r\n    const char* what() const noexcept override {\r\n        return \"Insufficient funds in account!\";\r\n    }\r\n    \r\n    double getAmount() { return amount; }\r\n};\r\n\r\nclass BankAccount {\r\n    double balance;\r\npublic:\r\n    BankAccount(double b) : balance(b) {}\r\n    \r\n    void withdraw(double amount) {\r\n        if (amount > balance) {\r\n            throw InsufficientFundsException(amount - balance);\r\n        }\r\n        balance -= amount;\r\n        cout << \"Withdrawn $\" << amount << \". New balance: $\" << balance << endl;\r\n    }\r\n};\r\n\r\nint main() {\r\n    BankAccount account(500.0);\r\n    try {\r\n        account.withdraw(200);  // OK\r\n        account.withdraw(400);  // Will throw!\r\n    } catch (const InsufficientFundsException& e) {\r\n        cout << e.what() << endl;\r\n        cout << \"You need $\" << e.getAmount() << \" more.\" << endl;\r\n    }\r\n    return 0;\r\n}\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/cpp/cppLesson7.js\n");

