eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   dsaLesson11: () => (/* binding */ dsaLesson11)\n/* harmony export */ });\nconst dsaLesson11 = {\n    id: 11,\n    title: \"String Algorithms & Pattern Matching\",\n    description: \"KMP, Rabin-Karp, substring matching, and more.\",\n    content: `\r\n## String Algorithms\r\n\r\nString problems are very common in interviews. Master these patterns!\r\n\r\n### Longest Common Substring:\r\n<COMPILER>\r\ndef longest_common_substring(s1, s2):\r\n    m, n = len(s1), len(s2)\r\n    dp = [[0] * (n + 1) for _ in range(m + 1)]\r\n    max_len = 0\r\n    \r\n    for i in range(1, m + 1):\r\n        for j in range(1, n + 1):\r\n            if s1[i - 1] == s2[j - 1]:\r\n                dp[i][j] = dp[i - 1][j - 1] + 1\r\n                max_len = max(max_len, dp[i][j])\r\n    \r\n    return max_len\r\n\r\ns1 = \"abcdef\"\r\ns2 = \"fbdefe\"\r\nprint(f\"LCS length: {longest_common_substring(s1, s2)}\")  # 3\r\n</COMPILER>\r\n\r\n### Palindrome Check:\r\n<COMPILER>\r\ndef is_palindrome(s):\r\n    cleaned = ''.join(c.lower() for c in s if c.isalnum())\r\n    return cleaned == cleaned[::-1]\r\n\r\ntest_strings = [\r\n    \"A man, a plan, a canal: Panama\",\r\n    \"racecar\",\r\n    \"hello\"\r\n]\r\n\r\nfor s in test_strings:\r\n    print(f'\"{s}\" is palindrome: {is_palindrome(s)}')\r\n</COMPILER>\r\n\r\n### Anagram Check:\r\n<COMPILER>\r\ndef is_anagram(s1, s2):\r\n    return sorted(s1) == sorted(s2)\r\n\r\n# Alternative using character count\r\ndef is_anagram_count(s1, s2):\r\n    from collections import Counter\r\n    return Counter(s1) == Counter(s2)\r\n\r\nprint(is_anagram(\"listen\", \"silent\"))     # True\r\nprint(is_anagram(\"hello\", \"world\"))       # False\r\nprint(is_anagram_count(\"abc\", \"cab\"))     # True\r\n</COMPILER>\r\n\r\n### Longest Substring Without Repeating Characters:\r\n<COMPILER>\r\ndef longest_substring_no_repeat(s):\r\n    char_index = {}\r\n    max_len = 0\r\n    start = 0\r\n    \r\n    for i, char in enumerate(s):\r\n        if char in char_index and char_index[char] >= start:\r\n            start = char_index[char] + 1\r\n        \r\n        max_len = max(max_len, i - start + 1)\r\n        char_index[char] = i\r\n    \r\n    return max_len\r\n\r\nstrings = [\"abcabcbb\", \"au\", \"dvdf\", \"pwwkew\"]\r\nfor s in strings:\r\n    print(f\"'{s}' -> {longest_substring_no_repeat(s)}\")\r\n</COMPILER>\r\n\r\n### Word Break Problem:\r\n<COMPILER>\r\ndef word_break(s, word_dict):\r\n    dp = [False] * (len(s) + 1)\r\n    dp[0] = True\r\n    \r\n    for i in range(1, len(s) + 1):\r\n        for j in range(i):\r\n            if dp[j] and s[j:i] in word_dict:\r\n                dp[i] = True\r\n                break\r\n    \r\n    return dp[len(s)]\r\n\r\ns = \"catsandcatsdog\"\r\nword_dict = {\"cat\", \"cats\", \"and\", \"sand\", \"dog\"}\r\nprint(word_break(s, word_dict))  # True\r\n\r\ns2 = \"catsandog\"\r\nprint(word_break(s2, word_dict))  # False\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/dsa/dsaLesson11.js\n");

