eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   dsaLesson12: () => (/* binding */ dsaLesson12)\n/* harmony export */ });\nconst dsaLesson12 = {\n    id: 12,\n    title: \"Advanced DSA Topics\",\n    description: \"Tries, Union-Find, Segment Trees, and more advanced concepts.\",\n    content: `\r\n## Advanced Data Structures\r\n\r\n### Trie (Prefix Tree):\r\n<COMPILER>\r\nclass TrieNode:\r\n    def __init__(self):\r\n        self.children = {}\r\n        self.is_end = False\r\n\r\nclass Trie:\r\n    def __init__(self):\r\n        self.root = TrieNode()\r\n    \r\n    def insert(self, word):\r\n        node = self.root\r\n        for char in word:\r\n            if char not in node.children:\r\n                node.children[char] = TrieNode()\r\n            node = node.children[char]\r\n        node.is_end = True\r\n    \r\n    def search(self, word):\r\n        node = self.root\r\n        for char in word:\r\n            if char not in node.children:\r\n                return False\r\n            node = node.children[char]\r\n        return node.is_end\r\n    \r\n    def starts_with(self, prefix):\r\n        node = self.root\r\n        for char in prefix:\r\n            if char not in node.children:\r\n                return False\r\n            node = node.children[char]\r\n        return True\r\n\r\ntrie = Trie()\r\ntrie.insert(\"apple\")\r\ntrie.insert(\"app\")\r\nprint(\"search('apple'):\", trie.search(\"apple\"))      # True\r\nprint(\"search('app'):\", trie.search(\"app\"))          # True\r\nprint(\"starts_with('ap'):\", trie.starts_with(\"ap\"))  # True\r\nprint(\"search('appl'):\", trie.search(\"appl\"))        # False\r\n</COMPILER>\r\n\r\n### Union-Find (Disjoint Set Union):\r\n<COMPILER>\r\nclass UnionFind:\r\n    def __init__(self, n):\r\n        self.parent = list(range(n))\r\n        self.rank = [0] * n\r\n    \r\n    def find(self, x):\r\n        if self.parent[x] != x:\r\n            self.parent[x] = self.find(self.parent[x])  # Path compression\r\n        return self.parent[x]\r\n    \r\n    def union(self, x, y):\r\n        root_x = self.find(x)\r\n        root_y = self.find(y)\r\n        \r\n        if root_x == root_y:\r\n            return False\r\n        \r\n        # Union by rank\r\n        if self.rank[root_x] < self.rank[root_y]:\r\n            self.parent[root_x] = root_y\r\n        elif self.rank[root_x] > self.rank[root_y]:\r\n            self.parent[root_y] = root_x\r\n        else:\r\n            self.parent[root_y] = root_x\r\n            self.rank[root_x] += 1\r\n        \r\n        return True\r\n    \r\n    def is_connected(self, x, y):\r\n        return self.find(x) == self.find(y)\r\n\r\nuf = UnionFind(6)\r\nuf.union(0, 1)\r\nuf.union(1, 2)\r\nuf.union(3, 4)\r\n\r\nprint(\"0 and 2 connected:\", uf.is_connected(0, 2))  # True\r\nprint(\"0 and 3 connected:\", uf.is_connected(0, 3))  # False\r\n\r\nuf.union(2, 3)\r\nprint(\"After union(2,3), 0 and 3 connected:\", uf.is_connected(0, 3))  # True\r\n</COMPILER>\r\n\r\n### Segment Tree - Range Sum Query:\r\n<COMPILER>\r\nclass SegmentTree:\r\n    def __init__(self, arr):\r\n        self.n = len(arr)\r\n        self.tree = [0] * (4 * self.n)\r\n        self.build(arr, 0, 0, self.n - 1)\r\n    \r\n    def build(self, arr, node, start, end):\r\n        if start == end:\r\n            self.tree[node] = arr[start]\r\n        else:\r\n            mid = (start + end) // 2\r\n            self.build(arr, 2 * node + 1, start, mid)\r\n            self.build(arr, 2 * node + 2, mid + 1, end)\r\n            self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]\r\n    \r\n    def query(self, node, start, end, l, r):\r\n        if r < start or end < l:\r\n            return 0\r\n        if l <= start and end <= r:\r\n            return self.tree[node]\r\n        \r\n        mid = (start + end) // 2\r\n        left_sum = self.query(2 * node + 1, start, mid, l, r)\r\n        right_sum = self.query(2 * node + 2, mid + 1, end, l, r)\r\n        return left_sum + right_sum\r\n    \r\n    def range_sum(self, l, r):\r\n        return self.query(0, 0, self.n - 1, l, r)\r\n\r\narr = [1, 3, 5, 7, 9, 11]\r\nst = SegmentTree(arr)\r\nprint(\"Sum [0, 2]:\", st.range_sum(0, 2))  # 1 + 3 + 5 = 9\r\nprint(\"Sum [1, 4]:\", st.range_sum(1, 4))  # 3 + 5 + 7 + 9 = 24\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/dsa/dsaLesson12.js\n");

