eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   dsaLesson2: () => (/* binding */ dsaLesson2)\n/* harmony export */ });\nconst dsaLesson2 = {\n    id: 2,\n    title: \"Arrays & Hashing\",\n    description: \"Solving problems with arrays and hash maps efficiently.\",\n    content: `\r\n## Arrays & Hash Maps\r\n\r\nArrays and Hash Maps (Dictionaries) are the most frequently used data structures in coding interviews.\r\n\r\n### Two Sum Problem (Classic Interview Question!)\r\nGiven an array, find two numbers that add up to a target.\r\n\r\n<COMPILER>\r\n# Brute Force: O(n²) — check every pair\r\ndef two_sum_brute(nums, target):\r\n    for i in range(len(nums)):\r\n        for j in range(i + 1, len(nums)):\r\n            if nums[i] + nums[j] == target:\r\n                return [i, j]\r\n    return []\r\n\r\nnums = [2, 7, 11, 15]\r\ntarget = 9\r\nprint(two_sum_brute(nums, target))  # [0, 1]\r\n</COMPILER>\r\n\r\n### Optimal Solution with Hash Map:\r\n<COMPILER>\r\n# Optimal: O(n) — use a hash map to store complements\r\ndef two_sum(nums, target):\r\n    seen = {}  # value -> index\r\n    for i, num in enumerate(nums):\r\n        complement = target - num\r\n        if complement in seen:\r\n            return [seen[complement], i]\r\n        seen[num] = i\r\n    return []\r\n\r\nnums = [2, 7, 11, 15]\r\ntarget = 9\r\nprint(two_sum(nums, target))  # [0, 1]\r\n</COMPILER>\r\n\r\n### Sliding Window Technique:\r\n<COMPILER>\r\n# Find max sum of subarray of size k\r\ndef max_subarray_sum(arr, k):\r\n    window_sum = sum(arr[:k])\r\n    max_sum = window_sum\r\n    \r\n    for i in range(k, len(arr)):\r\n        window_sum += arr[i] - arr[i - k]  # Add new, remove old\r\n        max_sum = max(max_sum, window_sum)\r\n    \r\n    return max_sum\r\n\r\narr = [1, 4, 2, 10, 2, 3, 1, 0, 20]\r\nk = 4\r\nprint(max_subarray_sum(arr, k))  # 24\r\n</COMPILER>\r\n\r\n### Two Pointers:\r\n<COMPILER>\r\ndef has_pair_with_sum(arr, target):\r\n    arr.sort()\r\n    left, right = 0, len(arr) - 1\r\n    while left < right:\r\n        current = arr[left] + arr[right]\r\n        if current == target:\r\n            return True\r\n        elif current < target:\r\n            left += 1\r\n        else:\r\n            right -= 1\r\n    return False\r\n\r\narr = [2, 5, 8, 12, 16, 23]\r\ntarget = 18\r\nprint(has_pair_with_sum(arr, target))  # True (5 + 13? No, 2 + 16)\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/dsa/dsaLesson2.js\n");

