eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   dsaLesson3: () => (/* binding */ dsaLesson3)\n/* harmony export */ });\nconst dsaLesson3 = {\n    id: 3,\n    title: \"Linked Lists\",\n    description: \"Building and traversing singly and doubly linked lists.\",\n    content: `\r\n## Linked Lists\r\n\r\nA Linked List is a linear data structure where elements (nodes) are stored in separate memory locations, each node holding a value and a pointer to the next node.\r\n\r\n### Node & LinkedList Setup:\r\n<COMPILER>\r\nclass Node:\r\n    def __init__(self, val):\r\n        self.val = val\r\n        self.next = None\r\n\r\nclass LinkedList:\r\n    def __init__(self):\r\n        self.head = None\r\n\r\n    def append(self, val):\r\n        new_node = Node(val)\r\n        if not self.head:\r\n            self.head = new_node\r\n            return\r\n        current = self.head\r\n        while current.next:  # Traverse to the tail\r\n            current = current.next\r\n        current.next = new_node\r\n\r\n    def display(self):\r\n        result = []\r\n        current = self.head\r\n        while current:\r\n            result.append(str(current.val))\r\n            current = current.next\r\n        return \" -> \".join(result)\r\n\r\nll = LinkedList()\r\nll.append(1)\r\nll.append(2)\r\nll.append(3)\r\nprint(ll.display())  # 1 -> 2 -> 3\r\n</COMPILER>\r\n\r\n### Reversing a Linked List (Interview Classic!):\r\n<COMPILER>\r\nclass Node:\r\n    def __init__(self, val):\r\n        self.val = val\r\n        self.next = None\r\n\r\ndef reverse_list(head):\r\n    prev = None\r\n    current = head\r\n    while current:\r\n        next_node = current.next  # Save next\r\n        current.next = prev       # Reverse pointer\r\n        prev = current            # Move prev forward\r\n        current = next_node       # Move current forward\r\n    return prev  # prev is now the new head\r\n\r\ndef display(head):\r\n    result = []\r\n    while head:\r\n        result.append(str(head.val))\r\n        head = head.next\r\n    return \" -> \".join(result)\r\n\r\n# Create list: 1 -> 2 -> 3\r\nhead = Node(1)\r\nhead.next = Node(2)\r\nhead.next.next = Node(3)\r\nprint(\"Original:\", display(head))\r\nhead = reverse_list(head)\r\nprint(\"Reversed:\", display(head))\r\n</COMPILER>\r\n\r\n### Detect a Cycle (Floyd's Algorithm):\r\n<COMPILER>\r\nclass Node:\r\n    def __init__(self, val):\r\n        self.val = val\r\n        self.next = None\r\n\r\ndef has_cycle(head):\r\n    slow = head\r\n    fast = head\r\n    while fast and fast.next:\r\n        slow = slow.next       # Moves 1 step\r\n        fast = fast.next.next  # Moves 2 steps\r\n        if slow == fast:       # They meet only if there's a cycle\r\n            return True\r\n    return False\r\n\r\n# Create list: 1 -> 2 -> 3 -> 2 (cycle)\r\nhead = Node(1)\r\nnode2 = Node(2)\r\nnode3 = Node(3)\r\nhead.next = node2\r\nnode2.next = node3\r\nnode3.next = node2  # Create cycle\r\n\r\nprint(\"Has cycle:\", has_cycle(head))  # True\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/dsa/dsaLesson3.js\n");

