eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   dsaLesson6: () => (/* binding */ dsaLesson6)\n/* harmony export */ });\nconst dsaLesson6 = {\n    id: 6,\n    title: \"Trees & Binary Search Trees\",\n    description: \"Hierarchical data structures and BST operations.\",\n    content: `\r\n## Trees & Binary Search Trees\r\n\r\n### Tree Basics\r\nA **Tree** is a hierarchical data structure with a root node and child nodes forming a parent-child relationship. A **Binary Search Tree (BST)** is a special tree where left child < parent < right child.\r\n\r\n### TreeNode Definition:\r\n<COMPILER>\r\nclass TreeNode:\r\n    def __init__(self, val=0):\r\n        self.val = val\r\n        self.left = None\r\n        self.right = None\r\n\r\n# Create a simple tree:\r\n#       1\r\n#      / \\\\\r\n#     2   3\r\nroot = TreeNode(1)\r\nroot.left = TreeNode(2)\r\nroot.right = TreeNode(3)\r\n\r\nprint(\"Root:\", root.val)\r\nprint(\"Left child:\", root.left.val)\r\nprint(\"Right child:\", root.right.val)\r\n</COMPILER>\r\n\r\n### Inorder Traversal (Left-Root-Right):\r\n<COMPILER>\r\nclass TreeNode:\r\n    def __init__(self, val=0):\r\n        self.val = val\r\n        self.left = None\r\n        self.right = None\r\n\r\ndef inorder(root):\r\n    result = []\r\n    if root:\r\n        result += inorder(root.left)\r\n        result.append(root.val)\r\n        result += inorder(root.right)\r\n    return result\r\n\r\n# Create BST:\r\n#       2\r\n#      / \\\\\r\n#     1   3\r\nroot = TreeNode(2)\r\nroot.left = TreeNode(1)\r\nroot.right = TreeNode(3)\r\n\r\nprint(\"Inorder traversal:\", inorder(root))  # [1, 2, 3]\r\n</COMPILER>\r\n\r\n### Search in BST:\r\n<COMPILER>\r\nclass TreeNode:\r\n    def __init__(self, val=0):\r\n        self.val = val\r\n        self.left = None\r\n        self.right = None\r\n\r\ndef search_bst(root, val):\r\n    if not root:\r\n        return False\r\n    if root.val == val:\r\n        return True\r\n    elif val < root.val:\r\n        return search_bst(root.left, val)\r\n    else:\r\n        return search_bst(root.right, val)\r\n\r\n# Create BST:\r\nroot = TreeNode(4)\r\nroot.left = TreeNode(2)\r\nroot.right = TreeNode(6)\r\nroot.left.left = TreeNode(1)\r\nroot.left.right = TreeNode(3)\r\n\r\nprint(\"Search 3:\", search_bst(root, 3))  # True\r\nprint(\"Search 5:\", search_bst(root, 5))  # False\r\n</COMPILER>\r\n\r\n### Level Order Traversal (BFS):\r\n<COMPILER>\r\nfrom collections import deque\r\n\r\nclass TreeNode:\r\n    def __init__(self, val=0):\r\n        self.val = val\r\n        self.left = None\r\n        self.right = None\r\n\r\ndef level_order(root):\r\n    if not root:\r\n        return []\r\n    \r\n    result = []\r\n    queue = deque([root])\r\n    \r\n    while queue:\r\n        node = queue.popleft()\r\n        result.append(node.val)\r\n        \r\n        if node.left:\r\n            queue.append(node.left)\r\n        if node.right:\r\n            queue.append(node.right)\r\n    \r\n    return result\r\n\r\n# Create tree:\r\nroot = TreeNode(1)\r\nroot.left = TreeNode(2)\r\nroot.right = TreeNode(3)\r\nroot.left.left = TreeNode(4)\r\n\r\nprint(\"Level order:\", level_order(root))  # [1, 2, 3, 4]\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/dsa/dsaLesson6.js\n");

