eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   html_cssLesson8: () => (/* binding */ html_cssLesson8)\n/* harmony export */ });\nconst html_cssLesson8 = {\n    id: 8,\n    title: \"CSS Variables & Custom Properties\",\n    description: \"Building scalable design systems with CSS custom properties.\",\n    content: `\r\n## CSS Custom Properties (Variables)\r\n\r\nCSS Variables (officially called Custom Properties) let you define reusable values in one place and reference them throughout your stylesheet. They're the backbone of any professional design system.\r\n\r\n### Defining and Using Variables:\r\n\\`\\`\\`css\r\n/* Variables are typically defined on the :root pseudo-class\r\n   so they are globally accessible */\r\n:root {\r\n    /* Colors */\r\n    --color-primary: #3b82f6;\r\n    --color-primary-dark: #1d4ed8;\r\n    --color-text: #1f2937;\r\n    --color-text-muted: #6b7280;\r\n    --color-bg: #ffffff;\r\n    --color-bg-secondary: #f9fafb;\r\n    --color-border: #e5e7eb;\r\n    \r\n    /* Spacing */\r\n    --spacing-sm: 8px;\r\n    --spacing-md: 16px;\r\n    --spacing-lg: 24px;\r\n    --spacing-xl: 32px;\r\n    \r\n    /* Typography */\r\n    --font-size-sm: 0.875rem;\r\n    --font-size-base: 1rem;\r\n    --font-size-lg: 1.25rem;\r\n    --font-size-xl: 1.5rem;\r\n    \r\n    /* Shadows */\r\n    --shadow-sm: 0 1px 2px rgba(0,0,0,0.05);\r\n    --shadow-md: 0 4px 6px rgba(0,0,0,0.07);\r\n    --shadow-lg: 0 10px 25px rgba(0,0,0,0.1);\r\n    \r\n    /* Border Radius */\r\n    --radius-sm: 4px;\r\n    --radius-md: 8px;\r\n    --radius-lg: 16px;\r\n    --radius-full: 9999px;\r\n}\r\n\r\n/* Use the variable with var() */\r\n.button {\r\n    background: var(--color-primary);\r\n    color: white;\r\n    padding: var(--spacing-sm) var(--spacing-md);\r\n    border-radius: var(--radius-md);\r\n    box-shadow: var(--shadow-md);\r\n    font-size: var(--font-size-base);\r\n}\r\n\r\n.button:hover {\r\n    background: var(--color-primary-dark);\r\n}\r\n\\`\\`\\`\r\n\r\n### Dark Mode with CSS Variables:\r\n\\`\\`\\`css\r\n:root {\r\n    --bg: #ffffff;\r\n    --text: #1f2937;\r\n    --card-bg: #f9fafb;\r\n}\r\n\r\n/* Override variables for dark mode */\r\n[data-theme=\"dark\"],\r\n@media (prefers-color-scheme: dark) {\r\n    :root {\r\n        --bg: #0f172a;\r\n        --text: #e2e8f0;\r\n        --card-bg: #1e293b;\r\n    }\r\n}\r\n\r\nbody {\r\n    background: var(--bg);\r\n    color: var(--text);\r\n    transition: background 0.3s, color 0.3s;\r\n}\r\n\r\n.card {\r\n    background: var(--card-bg);\r\n}\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/html_css/html_cssLesson8.js\n");

