(counter()); // 3 — 'count' is preserved!\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/javascript/javascriptLesson2.js\n");

