eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   pythonLesson5: () => (/* binding */ pythonLesson5)\n/* harmony export */ });\nconst pythonLesson5 = {\n    id: 5,\n    title: \"Modules, Packages & Popular Libraries\",\n    description: \"Import modules, create packages, and use NumPy, Pandas, Requests\",\n    content: `\r\n## Modules and Packages\r\n\r\nA module is a Python file containing code. A package is a directory containing modules.\r\n\r\n### Built-in Modules:\r\n\r\n\\`\\`\\`python\r\n# Math operations\r\nimport math\r\nprint(math.sqrt(16))     # 4.0\r\nprint(math.pi)           # 3.141592653589793\r\n\r\n# Random numbers\r\nimport random\r\nprint(random.randint(1, 10))  # Random int between 1-10\r\nprint(random.choice([1, 2, 3, 4, 5]))  # Random element\r\n\r\n# Date and Time\r\nfrom datetime import datetime, timedelta\r\nnow = datetime.now()\r\ntomorrow = now + timedelta(days=1)\r\nprint(now.strftime(\"%Y-%m-%d %H:%M:%S\"))\r\n\r\n# Working with strings\r\nimport string\r\nprint(string.ascii_letters)     # 'abcdefghijklmnopqrstuvwxyzABC...'\r\nprint(string.digits)            # '0123456789'\r\n\\`\\`\\`\r\n\r\n### Importing Different Ways:\r\n\r\n\\`\\`\\`python\r\n# Import entire module\r\nimport math\r\nresult = math.sqrt(9)\r\n\r\n# Import specific items\r\nfrom math import sqrt, pi\r\nresult = sqrt(9)\r\n\r\n# Import with alias\r\nimport numpy as np\r\narr = np.array([1, 2, 3])\r\n\r\n# Import everything (not recommended!)\r\nfrom math import *\r\nresult = sqrt(9)  # 'sqrt' is directly available\r\n\\`\\`\\`\r\n\r\n### Creating Your Own Module:\r\n\r\n\\`\\`\\`python\r\n# calculator.py\r\ndef add(a, b):\r\n    return a + b\r\n\r\ndef subtract(a, b):\r\n    return a - b\r\n\r\nPI = 3.14159\r\n\r\n# main.py\r\nimport calculator\r\nprint(calculator.add(5, 3))\r\n\\`\\`\\`\r\n\r\n## Popular Libraries\r\n\r\n### NumPy (Numerical Python):\r\n\r\n\\`\\`\\`python\r\nimport numpy as np\r\n\r\n# Create arrays\r\narr = np.array([1, 2, 3, 4, 5])\r\nmatrix = np.array([[1, 2, 3], [4, 5, 6]])\r\n\r\n# Operations\r\nprint(arr.mean())   # Average\r\nprint(arr.sum())    # Sum\r\nprint(arr.shape)    # (5,)\r\nprint(matrix.shape) # (2, 3)\r\n\r\n# Indexing and slicing\r\nprint(arr[0])       # 1\r\nprint(arr[1:3])     # [2, 3]\r\n\r\n# Mathematical operations\r\nprint(arr * 2)      # [2, 4, 6, 8, 10]\r\nprint(arr ** 2)     # [1, 4, 9, 16, 25]\r\n\\`\\`\\`\r\n\r\n### Pandas (Data Analysis):\r\n\r\n\\`\\`\\`python\r\nimport pandas as pd\r\n\r\n# Create DataFrame\r\ndata = {\r\n    \"Name\": [\"Alice\", \"Bob\", \"Charlie\"],\r\n    \"Age\": [25, 30, 35],\r\n    \"City\": [\"NYC\", \"LA\", \"Chicago\"]\r\n}\r\ndf = pd.DataFrame(data)\r\n\r\nprint(df)\r\nprint(df[\"Name\"])     # Get column\r\nprint(df.loc[0])      # Get row by index\r\nprint(df[df[\"Age\"] > 25])  # Filter rows\r\n\r\n# Reading CSV\r\ndf = pd.read_csv(\"data.csv\")\r\n\r\n# Basic operations\r\nprint(df.describe())  # Statistical summary\r\nprint(df.head())      # First 5 rows\r\nprint(df.tail())      # Last 5 rows\r\n\\`\\`\\`\r\n\r\n### Requests (HTTP Library):\r\n\r\n\\`\\`\\`python\r\nimport requests\r\n\r\n# GET request\r\nresponse = requests.get(\"https://api.example.com/users\")\r\nprint(response.status_code)  # 200\r\nprint(response.json())       # Parse JSON response\r\nprint(response.text)         # Raw text\r\n\r\n# POST request\r\ndata = {\"name\": \"Alice\", \"age\": 25}\r\nresponse = requests.post(\"https://api.example.com/users\", json=data)\r\n\r\n# Headers\r\nheaders = {\"User-Agent\": \"MyApp/1.0\"}\r\nresponse = requests.get(\"https://api.example.com\", headers=headers)\r\n\\`\\`\\`\r\n\r\n### Regular Expressions (Regex):\r\n\r\n\\`\\`\\`python\r\nimport re\r\n\r\ntext = \"Email: alice@example.com, bob@test.org\"\r\n\r\n# Find all emails\r\nemails = re.findall(r\"[\\\\w.-]+@[\\\\w.-]+\\\\.\\\\w+\", text)\r\nprint(emails)  # ['alice@example.com', 'bob@test.org']\r\n\r\n# Match\r\nif re.match(r\"\\\\d{3}-\\\\d{3}-\\\\d{4}\", \"123-456-7890\"):\r\n    print(\"Valid phone number\")\r\n\r\n# Replace\r\ntext = re.sub(r\"\\\\d+\", \"X\", \"abc123def456\")\r\nprint(text)  # abcXdefX\r\n\r\n# Split\r\nwords = re.split(r\"\\\\s+\", \"Hello   world  python\")\r\nprint(words)  # ['Hello', 'world', 'python']\r\n\\`\\`\\`\r\n\r\n## Installation & Virtual Environments:\r\n\r\n\\`\\`\\`bash\r\n# pip: Python package manager\r\npip install numpy\r\npip install pandas requests\r\n\r\n# List installed packages\r\npip list\r\n\r\n# Virtual Environment (isolate dependencies)\r\npython -m venv myenv\r\n\r\n# Activate (Windows)\r\nmyenv\\\\Scripts\\\\activate\r\n\r\n# Activate (Mac/Linux)\r\nsource myenv/bin/activate\r\n\r\n# Freeze dependencies\r\npip freeze > requirements.txt\r\n\r\n# Install from file\r\npip install -r requirements.txt\r\n\\`\\`\\`\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/python/pythonLesson5.js\n");

