eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   pythonLesson6: () => (/* binding */ pythonLesson6)\n/* harmony export */ });\nconst pythonLesson6 = {\n    id: 6,\n    title: \"Decorators & Generators\",\n    description: \"Advanced function concepts: decorators and generator functions.\",\n    content: `\r\n## Decorators\r\n\r\nA decorator is a function that modifies another function or class. Decorators are a powerful way to \"wrap\" a function.\r\n\r\n### Simple Decorators:\r\n<COMPILER>\r\ndef simple_decorator(func):\r\n    def wrapper():\r\n        print(\"Before function call\")\r\n        func()\r\n        print(\"After function call\")\r\n    return wrapper\r\n\r\n@simple_decorator\r\ndef greet():\r\n    print(\"Hello!\")\r\n\r\ngreet()\r\n# Output:\r\n# Before function call\r\n# Hello!\r\n# After function call\r\n</COMPILER>\r\n\r\n### Decorators with Arguments:\r\n<COMPILER>\r\ndef repeat_decorator(times):\r\n    def decorator(func):\r\n        def wrapper(*args, **kwargs):\r\n            for _ in range(times):\r\n                result = func(*args, **kwargs)\r\n            return result\r\n        return wrapper\r\n    return decorator\r\n\r\n@repeat_decorator(3)\r\ndef say_hello():\r\n    print(\"Hello!\")\r\n\r\nsay_hello()\r\n# Output: Hello! Hello! Hello!\r\n</COMPILER>\r\n\r\n### Using functools.wraps:\r\n<COMPILER>\r\nfrom functools import wraps\r\n\r\ndef my_decorator(func):\r\n    @wraps(func)\r\n    def wrapper(*args, **kwargs):\r\n        \"\"\"Wrapper docstring\"\"\"\r\n        print(f\"Calling {func.__name__}\")\r\n        return func(*args, **kwargs)\r\n    return wrapper\r\n\r\n@my_decorator\r\ndef add(a, b):\r\n    \"\"\"Add two numbers\"\"\"\r\n    return a + b\r\n\r\nprint(add(3, 5))  # 8\r\nprint(add.__name__)  # 'add' (preserved by @wraps)\r\n</COMPILER>\r\n\r\n## Generators\r\n\r\nA generator is a function that returns values one at a time instead of storing all in memory.\r\n\r\n### Generator Functions:\r\n<COMPILER>\r\ndef count_up_to(n):\r\n    count = 1\r\n    while count <= n:\r\n        yield count\r\n    count += 1\r\n\r\n# Using the generator\r\nfor num in count_up_to(3):\r\n    print(num)\r\n# Output: 1, 2, 3\r\n\r\n# Get values manually\r\ngen = count_up_to(3)\r\nprint(next(gen))  # 1\r\nprint(next(gen))  # 2\r\nprint(next(gen))  # 3\r\n</COMPILER>\r\n\r\n### Generator Expressions:\r\n<COMPILER>\r\n# List comprehension (stores all in memory)\r\nsquares_list = [x**2 for x in range(5)]\r\n\r\n# Generator expression (lazy evaluation)\r\nsquares_gen = (x**2 for x in range(5))\r\n\r\n# Process one at a time\r\nfor square in squares_gen:\r\n    print(square)\r\n# Output: 0, 1, 4, 9, 16\r\n\r\n# Advantage: Memory efficient for large datasets\r\ndef infinite_count():\r\n    n = 1\r\n    while True:\r\n        yield n\r\n        n += 1\r\n\r\ncounter = infinite_count()\r\nprint(next(counter))  # 1\r\nprint(next(counter))  # 2\r\nprint(next(counter))  # 3\r\n</COMPILER>\r\n`\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/utils/learncourses/python/pythonLesson6.js\n");

